  public boolean isOperationSuccess(ProvisioningPlan.AccountRequest.Operation operation, ProvisioningPlan plan, ProvisioningResult result){
    logger.trace("Entering into isOperationSuccess");
    boolean isSuccess = false;
    if(plan!=null){
      List accountRequests = plan.getAccountRequests();
      if(accountRequests!=null){
        for(AccountRequest accountRequest : accountRequests){
          if(accountRequest!=null && operation.equals(accountRequest.getOperation())){
            ProvisioningResult  planResult = accountRequest.getResult();
            if((planResult!=null  && planResult.isCommitted()) || (result!=null  && result.isCommitted())){ 
              isSuccess = true;
              break;
            }

          }

        }
      }
    }
    logger.trace("Exiting into isOperationSuccess");
    return isSuccess;

  }
  void sendNotificationForWorkgroup(Identity mailRecipientIdentity, Map emailArguments, EmailTemplate emailTemplate) {

    //ClassLoader currentCl = Thread.currentThread().getContextClassLoader();
    //ClassLoader bakcedUpCl = null;
    //if(currentCl instanceof ConnectorClassLoader){
      //bakcedUpCl = currentCl;
      //Thread.currentThread().setContextClassLoader(currentCl.getParent());
    //}

    logger.trace("Entering sendNotificationForWorkgroup()");
    if (null != mailRecipientIdentity && null != mailRecipientIdentity && null != emailTemplate) {
      List workgroupMembers = null;
      EmailOptions emailOptions = null;
      emailOptions = new EmailOptions();
      emailOptions.addVariables(emailArguments);
      logger.trace("Notification setting for workgroup " + mailRecipientIdentity.getName() + " is " + mailRecipientIdentity.getNotificationOption());
      try {
        if (WorkgroupNotificationOption.Disabled.equals(mailRecipientIdentity.getNotificationOption())) {
          logger.trace("Notification is disabled for workgroup " + mailRecipientIdentity.getName());
        } else if (WorkgroupNotificationOption.GroupEmailOnly.equals(mailRecipientIdentity.getNotificationOption())) {
          String wgEmail = mailRecipientIdentity.getEmail();
          if (null != wgEmail && !wgEmail.trim().isEmpty()) {
            logger.trace("Sending email to: " + wgEmail);
            emailOptions.setTo(wgEmail);
            try {
              context.sendEmailNotification(emailTemplate, emailOptions);
            } catch (EmailException e) {
              logger.error("Exception occured while sending mail", e);
            } catch (GeneralException e) {
              logger.error("Exception occured", e);
            }
          } else {
            logger.trace("Group email is not provided for workgroup " + mailRecipientIdentity.getName());
          }
        } else if (WorkgroupNotificationOption.MembersOnly.equals(mailRecipientIdentity.getNotificationOption())) {
          workgroupMembers = getWorkgroupMemberNames(mailRecipientIdentity);
          List memberEmailList = new ArrayList();
          for (String currentMember : workgroupMembers) {
            Identity currentMemberIdentity = context.getObjectByName(Identity.class, currentMember);
            if (null != currentMemberIdentity) {
              String currentMemberEmail = currentMemberIdentity.getEmail();
              if (null != currentMemberEmail && !currentMemberEmail.trim().isEmpty()) {
                logger.trace("Found email " + currentMemberEmail + " for user " + currentMemberIdentity.getName());
                memberEmailList.add(currentMemberEmail);
              } else {
                logger.trace("User " + currentMemberIdentity.getName() + " does not have email");
              }
            }
          }
          if (!memberEmailList.isEmpty()) {
            for (String currentEmail : memberEmailList) {
              logger.trace("Sending email to: " + currentEmail);
              emailOptions.setTo(currentEmail);
              try {
                context.sendEmailNotification(emailTemplate, emailOptions);
              } catch (EmailException e) {
                logger.error("Exception occured while sending mail", e);
              } catch (GeneralException e) {
                logger.error("Exception occured", e);
              }
            }
          } else {
            logger.trace("Notifier address list is empty");
          }
        } else if (WorkgroupNotificationOption.Both.equals(mailRecipientIdentity.getNotificationOption())) {
          List memberEmailList = new ArrayList();
          String wgEmail = mailRecipientIdentity.getEmail();
          if (null != wgEmail && !wgEmail.trim().isEmpty()) {
            logger.trace("Adding workgroup email: " + wgEmail);
            memberEmailList.add(wgEmail);
          } else {
            logger.trace("Group email is not provided for workgroup " + mailRecipientIdentity.getName());
          }
          workgroupMembers = getWorkgroupMemberNames(mailRecipientIdentity);
          for (String currentMember : workgroupMembers) {
            Identity currentMemberIdentity = context.getObjectByName(Identity.class, currentMember);
            if (null != currentMemberIdentity) {
              String currentMemberEmail = currentMemberIdentity.getEmail();
              if (null != currentMemberEmail && !currentMemberEmail.trim().isEmpty()) {
                logger.trace("Found email " + currentMemberEmail + " for user "
                             + currentMemberIdentity.getName());
                memberEmailList.add(currentMemberEmail);
              } else {
                logger.trace("User " + currentMemberIdentity.getName() + " does not have email");
              }
            }
          }
          if (!memberEmailList.isEmpty()) {
            for (String currentEmail : memberEmailList) {
              logger.trace("Sending email to: " + currentEmail);
              emailOptions.setTo(currentEmail);
              try {
                context.sendEmailNotification(emailTemplate, emailOptions);
              } catch (EmailException e) {
                logger.error("Exception occured while sending mail", e);
              } catch (GeneralException e) {
                logger.error("Exception occured", e);
              }
            }
          } else {
            logger.trace("Notifier address list is empty");
          }
        } else {
          logger.trace("Notification option not provided for workgroup " + mailRecipientIdentity.getName());
        }
      } catch (Exception e) {
        logger.error("Exception occured while sending mail", e);
      }
    } else {
      logger.error("mailRecipientIdentity or emailArguments or emailTemplate was null. Cannot proceed with sending mail.");
    }
    logger.trace("Exiting sendNotificationForWorkgroup()");
  }

  String getUserDetails(String nativeID) {

    String userDetails = "";
    logger.debug("Native identitity in update rule "+nativeIdn);
    if ( null == application ) {
      throw new RuntimeException("Voalte Application details does not exist in IIQ ");
    }
    String finalUrl = application.getAttributeValue("genericWebServiceBaseUrl") + "users?search_filter_value=username&search_value="+nativeID;

    URL url = new URL(finalUrl);
    if( url != null) {
      try {
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        if (null != conn) {
          conn.setRequestMethod("GET");
          conn.setRequestProperty("Content-Type", "application/json");
          conn.setRequestProperty("Accept", "application/json");
          Map property=requestEndPoint.getHeader();
          String authHeader=	property.get("Authorization");

          conn.setRequestProperty("Authorization", authHeader);

          int responseCode = conn.getResponseCode();

          if(responseCode != HttpURLConnection.HTTP_OK) {
            throw new RuntimeException("Minting Svc Failed: Received HTTP Code " + responseCode);
          }

          BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()));
          logger.debug("END : getUserDetails");

          userDetails = br.readLine();
          br.close();
        }
      } catch(IOException e) {
        logger.error("IO Exceptions while retrieving users existing details "+e.getMessage());
      } catch(Exception e) {
        logger.error("Exceptions while retrieving users existing details "+e.getMessage());
      }
    } else {
      logger.error("Unable to get retrieve URL details ");
    }
    return userDetails;
  }

  public String getAttributesOfLink(String appName, String identityName)  throws GeneralException{
    logger.info("Entering method getAttributesOfLink");
    Attributes attrs = null;
    if(Util.isNullOrEmpty(appName)){
      attrs = new Attributes();
      return " ";
    }

    if(Util.isNullOrEmpty(identityName)){
      return " ";
    }

    Filter ftApp = Filter.eq("application.name", appName);
    Filter ftId = Filter.eq("identity.name", identityName);
    QueryOptions qpO = new QueryOptions();
    qpO.add(ftApp, ftId);

    Iterator iteSearch = context.search(Link.class, qpO, "attributes");

    while (iteSearch.hasNext()) {
      attrs =  iteSearch.next()[0];

    }
    Util.flushIterator(iteSearch);
    logger.info("Exiting method getAttributesOfLink");
    String userid=attrs.get("id");
    return userid;
  }

  public String createSession(){

