        " \"username\" : \""sailpoint"\"\r\n" +     
        "}";

    String url = "https://in.voalte.ascension.org/rest/v2/sessions#json";

    MediaType JSON = MediaType.parse("application/json");

    OkHttpClient client = new OkHttpClient();

    RequestBody body = RequestBody.create(JSON, json);
    Request request = new Request.Builder().url(url).method("POST",body).addHeader("Accept","application/json").addHeader("Content-Type","application/json").build();
    Response response = client.newCall(request).execute();
    String obj = response.body().string();
    org.json.JSONObject jsonVal = new org.json.JSONObject(obj);

    String sessionValue = (String) jsonVal.get("session_token");
    int sidValue = jsonVal.get("sid");
    String userType = (String) jsonVal.get("user_type");
    int userId =  jsonVal.get("user_id");

    return sessionValue;

  }
